  ('dietitian-moex-08984', 'dietitian', 'dietitian-moex-097-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '美國國家健康統計中心（NCHS）透過下列那一項調查，提供美國國民的飲食、營養健康資料，並執行營養 監測計畫？', '["NutritionandDietSurvey（NADS）", "NationalDietandNutritionSurvey（NDANS）", "NationalHealthandNutritionExaminationSurvey（NHANES）", "FoodBalanceSheet"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:51+00:00", "source_pdf_sha1": "34e0fd1a99f2", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "097140", "c": "113", "s": "5001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公共衛生營養學", "year": "097", "exam_name": "097年第二次專技醫事人員、中醫師、心理師、營養師、獸醫佐考試暨醫師分試、法醫師考試", "original_question_number": 34, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-08985', 'dietitian', 'dietitian-moex-097-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '針對社區老人以24小時回憶法進行營養評估，所獲得調查群體的每人每日營養素攝取量，可與那一個資料 進行比較，以了解老人的營養素攝取是否均衡？', '["國人膳食營養素參考攝取量", "國民飲食指標", "食物平衡表", "每日飲食指南"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:51+00:00", "source_pdf_sha1": "34e0fd1a99f2", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "097140", "c": "113", "s": "5001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公共衛生營養學", "year": "097", "exam_name": "097年第二次專技醫事人員、中醫師、心理師、營養師、獸醫佐考試暨醫師分試、法醫師考試", "original_question_number": 35, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-08986', 'dietitian', 'dietitian-moex-097-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '營養師透過跨理論模式（Transtheoretical model）來改善個案身體活動情形。他利用獎勵方式讓個案維持規 律性的身體活動，或鼓勵個案加入身體活動的俱樂部，並要求個案檢核每星期的身體活動次數。個案此時 的活動情形，最可能處於下列那一期？', '["行動期（action）", "準備期（preparation）", "思考期（contemplation）", "思考前期（precontemplation）"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:51+00:00", "source_pdf_sha1": "34e0fd1a99f2", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "097140", "c": "113", "s": "5001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公共衛生營養學", "year": "097", "exam_name": "097年第二次專技醫事人員、中醫師、心理師、營養師、獸醫佐考試暨醫師分試、法醫師考試", "original_question_number": 36, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-08987', 'dietitian', 'dietitian-moex-097-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '約有三成老人與五成學童的維生素B 營養狀況，屬於臨界缺乏。其原因最可能與下列那一類食品的攝取量 2 不足有關？', '["乳製品", "五穀類", "補充劑", "水果類"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:51+00:00", "source_pdf_sha1": "34e0fd1a99f2", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "097140", "c": "113", "s": "5001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公共衛生營養學", "year": "097", "exam_name": "097年第二次專技醫事人員、中醫師、心理師、營養師、獸醫佐考試暨醫師分試、法醫師考試", "original_question_number": 37, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-08988', 'dietitian', 'dietitian-moex-097-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '進行營養知識問卷分析時，最常使用的指標為何？① 敏感度（sensitivity） ② 複雜度（complexity）', '["鑑別度（itemdiscrimination）", "難度（itemdifficulty）", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:51+00:00", "source_pdf_sha1": "34e0fd1a99f2", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "097140", "c": "113", "s": "5001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公共衛生營養學", "year": "097", "exam_name": "097年第二次專技醫事人員、中醫師、心理師、營養師、獸醫佐考試暨醫師分試、法醫師考試", "original_question_number": 38, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-08989', 'dietitian', 'dietitian-moex-097-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '下列何者可用來測體內脂肪？① 雙能量X光吸收測量（DualEnergyX-rayAbsorptiometry,DEXA） ② 近紅', '["生物電阻法（Bioelectricalimpedancemethod）", "基本熱量測 量儀（IndirectCalorimeter）", "僅", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:51+00:00", "source_pdf_sha1": "34e0fd1a99f2", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "097140", "c": "113", "s": "5001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公共衛生營養學", "year": "097", "exam_name": "097年第二次專技醫事人員、中醫師、心理師、營養師、獸醫佐考試暨醫師分試、法醫師考試", "original_question_number": 39, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
